record_types.code:
type anon_anon_73 (discr : unsigned := 0) is record
   case discr is
      when 0 =>
         avl_table : aliased gsl.bst_avl
           .gsl_bst_avl_table;
      when others =>
         rb_table : aliased gsl.bst_rb
           .gsl_bst_rb_table;
   end case;
end record;

type anon_anon_75 (discr : unsigned := 0) is record
   case discr is
      when 0 =>
         avl_trav : aliased gsl.bst_avl
           .gsl_bst_avl_traverser;
      when others =>
         rb_trav : aliased gsl.bst_rb
           .gsl_bst_rb_traverser;
   end case;
end record;

type gsl_bst_trav is record
   c_type : access constant gsl_bst_type;
   trav_data : aliased anon_anon_75;
end record;

type gsl_bst_type is record
   name : Interfaces.C.Strings.chars_ptr;
   node_size : aliased size_t;
   init      : access function
     (arg1 : access constant gsl.bst_types.gsl_bst_allocator;
      arg2 : access function
        (arg1 : System.Address; arg2 : System.Address;
         arg3 : System.Address) return int;
      arg3 : System.Address; arg4 : System.Address)
      return int;
   nodes : access function
     (arg1 : System.Address)
      return size_t;
   insert : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   find : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   remove : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   empty : access function
     (arg1 : System.Address) return int;
   trav_init : access function
     (arg1 : System.Address; arg2 : System.Address)
      return int;
   trav_first : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   trav_last : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   trav_find : access function
     (arg1 : System.Address; arg2 : System.Address; arg3 : System.Address)
      return System.Address;
   trav_insert : access function
     (arg1 : System.Address; arg2 : System.Address; arg3 : System.Address)
      return System.Address;
   trav_copy : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
   trav_next : access function
     (arg1 : System.Address)
      return System.Address;
   trav_prev : access function
     (arg1 : System.Address)
      return System.Address;
   trav_cur : access function
     (arg1 : System.Address)
      return System.Address;
   trav_replace : access function
     (arg1 : System.Address; arg2 : System.Address)
      return System.Address;
end record;

type gsl_bst_workspace is record
   c_type : access constant gsl_bst_type;
   table  : aliased anon_anon_73;
end record;

subprograms.code:
function alloc
  (T         : access constant gsl_bst_type;
   allocator : access constant gsl.bst_types.gsl_bst_allocator;
   compare   : access function
     (arg1 : System.Address; arg2 : System.Address; arg3 : System.Address)
      return int;
   params : System.Address)
   return access gsl_bst_workspace
